import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import './ERPChatBot.css';

const Chatbot = ({ studentId }) => {
    const [messages, setMessages] = useState([]);
    const [input, setInput] = useState('');
    const [loading, setLoading] = useState(false);
    const messagesEndRef = useRef(null);

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    const handleSend = async () => {
        if (!input.trim() || loading) return;

        const userMessage = input.trim();
        setInput('');
        
        // Add user message
        setMessages(prev => [...prev, { text: userMessage, sender: 'user' }]);
        setLoading(true);

        try {
            const response = await axios.post('http://localhost:65000/api/chatbot/chat', {
                query: userMessage,
                studentId: studentId // Pass student ID from props
            });

            // Add bot response
            setMessages(prev => [...prev, { 
                text: response.data.response, 
                sender: 'bot',
                data: response.data.data
            }]);
        } catch (error) {
            console.error('Chatbot error:', error);
            setMessages(prev => [...prev, { 
                text: 'Sorry, I encountered an error. Please try again.', 
                sender: 'bot' 
            }]);
        } finally {
            setLoading(false);
        }
    };

    const handleKeyPress = (e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleSend();
        }
    };

    const renderMessage = (message, index) => {
        return (
            <div key={index} className={`message ${message.sender}`}>
                <div className="message-content">
                    <div className="message-text">{message.text}</div>
                    
                    {message.data && (
                        <div className="message-data">
                            {/* You can render additional data here if needed */}
                        </div>
                    )}
                </div>
            </div>
        );
    };

    return (
        <div className="chatbot-container">
            <div className="chatbot-header">
                <h3>ERP Assistant 🤖</h3>
                <p>Ask about fees, attendance, results, timetable, etc.</p>
            </div>
            
            <div className="chatbot-messages">
                {messages.length === 0 ? (
                    <div className="welcome-message">
                        <p>Hello! I'm your ERP assistant. I can help you with:</p>
                        <ul>
                            <li>💰 Fees and payments</li>
                            <li>📊 Attendance in your courses</li>
                            <li>📈 Results and grades</li>
                            <li>📅 Timetable and class schedule</li>
                            <li>📝 Assignments and tasks</li>
                            <li>📚 Enrolled courses</li>
                        </ul>
                        <p>Try asking: "What's my attendance in MATH101?"</p>
                    </div>
                ) : (
                    messages.map(renderMessage)
                )}
                
                {loading && (
                    <div className="message bot">
                        <div className="message-content">
                            <div className="typing-indicator">
                                <span></span>
                                <span></span>
                                <span></span>
                            </div>
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>
            
            <div className="chatbot-input">
                <textarea
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyPress={handleKeyPress}
                    placeholder="Ask me anything about your academics..."
                    rows="1"
                    disabled={loading}
                />
                <button onClick={handleSend} disabled={loading || !input.trim()}>
                    {loading ? '...' : 'Send'}
                </button>
            </div>
        </div>
    );
};

export default Chatbot;
